# test_final_state.py
import json
import os
import pytest

def test_final_output_exists():
    """Ensure the final output file was generated by the sink service."""
    assert os.path.exists("/tmp/final_output.json"), "The sink output file /tmp/final_output.json is missing."
    assert os.path.isfile("/tmp/final_output.json"), "/tmp/final_output.json is not a file."

def test_mse_metric():
    """Calculate the MSE between the agent's output and the golden data and assert it meets the threshold."""
    output_file = "/tmp/final_output.json"
    golden_file = "/app/golden.json"

    assert os.path.exists(output_file), f"Agent output file not found at {output_file}"
    assert os.path.exists(golden_file), f"Golden file not found at {golden_file}"

    with open(output_file, "r") as f:
        agent_data = [json.loads(line) for line in f if line.strip()]

    with open(golden_file, "r") as f:
        golden_data = [json.loads(line) for line in f if line.strip()]

    assert len(agent_data) == len(golden_data), (
        f"Length mismatch: agent produced {len(agent_data)} records, "
        f"but expected {len(golden_data)}."
    )

    mse = sum((a["value"] - g["value"])**2 for a, g in zip(agent_data, golden_data)) / len(golden_data)
    threshold = 0.001

    assert mse <= threshold, f"MSE {mse} exceeds the maximum allowed threshold of {threshold}."